index 0000000..f97eddb
--- /dev/null
+++ b/kernel-shared/src/com.rs
@@ -0,0 +1,109 @@
+//! Process counts and well-known endpoints.
+//!
+//! Matches MINIX 3 `include/minix/com.h`. Kernel tasks (`ASYNCM`, `IDLE`,
+//! `CLOCK`, `SYSTEM`, `HARDWARE`) live at negative process numbers; the
+//! system servers and other user-space processes live at non-negative
+//! process numbers in the order they boot.
+
+use crate::endpoint::{Endpoint, ProcNr, make_endpoint};
+
+/// Number of kernel tasks (slots with negative proc-numbers).
+pub const NR_TASKS: usize = 5;
+/// Number of user-process slots in the process table.
+pub const NR_PROCS: usize = 256;
+/// Number of slots in the privilege table — system (privileged) processes.
+pub const NR_SYS_PROCS: usize = 64;
+
+// ---------------------------------------------------------------------------
+// Kernel tasks — negative proc-numbers.
+// ---------------------------------------------------------------------------
+
+/// Asynchronous-message driver (kernel pseudo-task).
+pub const ASYNCM: ProcNr = -5;
+/// Idle task (runs when nothing else is runnable).
+pub const IDLE: ProcNr = -4;
+/// Clock task (kernel pseudo-task for timer-driven work).
+pub const CLOCK: ProcNr = -3;
+/// System task (handles `SYS_*` kernel calls).
+pub const SYSTEM: ProcNr = -2;
+/// Hardware-interrupt pseudo-task (source endpoint for IRQ notifications).
+pub const HARDWARE: ProcNr = -1;
+
+// ---------------------------------------------------------------------------
+// Well-known user-space servers — generation 0 at boot.
+// Order mirrors the MINIX 3 boot image.
+// ---------------------------------------------------------------------------
+
+pub const PM_PROC_NR: ProcNr = 0;
+pub const VFS_PROC_NR: ProcNr = 1;
+pub const RS_PROC_NR: ProcNr = 2;
+pub const MEM_PROC_NR: ProcNr = 3;
+pub const LOG_PROC_NR: ProcNr = 4;
+pub const TTY_PROC_NR: ProcNr = 5;
+pub const DS_PROC_NR: ProcNr = 6;
+pub const MFS_PROC_NR: ProcNr = 7;
+pub const VM_PROC_NR: ProcNr = 8;
+pub const PFS_PROC_NR: ProcNr = 9;
+pub const SCHED_PROC_NR: ProcNr = 10;
+pub const INIT_PROC_NR: ProcNr = 11;
+
+/// One past the highest boot-server proc-number (`init` is the last slot
+/// allocated from the boot image).
+pub const NR_BOOT_PROCS: usize = (INIT_PROC_NR as usize) + 1;
+
+// Compile-time guarantees that the proc tables can hold every boot process.
+const _: () = assert!(NR_PROCS >= NR_BOOT_PROCS);
+const _: () = assert!(NR_SYS_PROCS >= NR_BOOT_PROCS);
+
+/// Build a boot-time endpoint (generation 0) for a task or server.
+pub const fn boot_endpoint(p: ProcNr) -> Endpoint {
+    make_endpoint(0, p)
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+    use crate::endpoint::{endpoint_gen, endpoint_proc};
+
+    #[test]
+    fn task_endpoints_have_negative_procs() {
+        for p in [ASYNCM, IDLE, CLOCK, SYSTEM, HARDWARE] {
+            assert!(p < 0, "task proc {p} should be negative");
+        }
+    }
+
+    #[test]
+    fn server_endpoints_distinct_and_nonnegative() {
+        let servers = [
+            PM_PROC_NR, VFS_PROC_NR, RS_PROC_NR, MEM_PROC_NR, LOG_PROC_NR,
+            TTY_PROC_NR, DS_PROC_NR, MFS_PROC_NR, VM_PROC_NR, PFS_PROC_NR,
+            SCHED_PROC_NR, INIT_PROC_NR,
+        ];
+        for &p in &servers {
+            assert!(p >= 0, "server proc {p} should be non-negative");
+        }
+        let mut seen = [false; NR_BOOT_PROCS];
+        for &p in &servers {
+            let i = p as usize;
+            assert!(!seen[i], "duplicate proc_nr {p}");
+            seen[i] = true;
+        }
+    }
+
+    #[test]
+    fn boot_endpoint_roundtrips_for_tasks_and_servers() {
+        for p in [SYSTEM, IDLE, CLOCK, PM_PROC_NR, VFS_PROC_NR, INIT_PROC_NR] {
+            let e = boot_endpoint(p);
+            assert_eq!(endpoint_gen(e), 0);
+            assert_eq!(endpoint_proc(e), p);
+        }
+    }
+
+    #[test]
+    fn nr_boot_procs_covers_init() {
+        // `INIT_PROC_NR as usize` is constant so the comparison is also
+        // checked statically via `const _: () = assert!(...)` below; this
+        // test keeps the invariant visible at test-discovery time.
+        const { assert!(NR_BOOT_PROCS > INIT_PROC_NR as usize) };
+    }
+}
diff --git a/kernel-shared/src/endpoint.rs b/kernel-shared/src/endpoint.rs
new file mode 100644
index 0000000..3c8c026
--- /dev/null
+++ b/kernel-shared/src/endpoint.rs
@@ -0,0 +1,98 @@
+//! Endpoints and generation-aware proc-number encoding.
+//!
+//! An `Endpoint` is the kernel's name for a process. It encodes both the
+//! process-table slot (`ProcNr`) and a generation counter (`GenNr`) so that
+//! a slot reuse after a process exit produces a distinct endpoint. This
+//! catches stale-endpoint bugs in user-space code.
+//!
+//! Mirrors MINIX 3 `include/minix/type.h` (`typedef int endpoint_t`) and
+//! `include/minix/endpoint.h` (the `_ENDPOINT(g, n)` / `_ENDPOINT_P(e)` /
+//! `_ENDPOINT_G(e)` macros).
+
+/// Kernel-assigned identifier for a process; encodes generation + proc_nr.
+pub type Endpoint = i32;
+
+/// Index into the process table. Task slots are negative (`SYSTEM=-2`, …);
+/// user-process slots are non-negative.
+pub type ProcNr = i32;
+
+/// Generation counter — bumped when a process slot is reused.
+pub type GenNr = i32;
+
+/// Special endpoint matching any sender (used as the `src` argument to
+/// `RECEIVE`).
+pub const ANY: Endpoint = 0x7ace;
+
+/// Special endpoint referring to the calling process itself.
+pub const SELF: Endpoint = 0x8ace;
+
+/// Special endpoint meaning "no process".
+pub const NONE: Endpoint = 0x6ace;
+
+const ENDPOINT_GEN_SHIFT: i32 = 15;
+const ENDPOINT_PROC_MASK: i32 = (1 << ENDPOINT_GEN_SHIFT) - 1;
+
+/// Encode `(generation, proc_nr)` into an endpoint.
+pub const fn make_endpoint(g: GenNr, p: ProcNr) -> Endpoint {
+    (g << ENDPOINT_GEN_SHIFT) | (p & ENDPOINT_PROC_MASK)
+}
+
+/// Extract the process-table slot number from an endpoint, sign-extending
+/// the lower `ENDPOINT_GEN_SHIFT` bits so that task slots come back negative.
+pub const fn endpoint_proc(e: Endpoint) -> ProcNr {
+    let masked = e & ENDPOINT_PROC_MASK;
+    let sign_bit = 1 << (ENDPOINT_GEN_SHIFT - 1);
+    if masked & sign_bit != 0 {
+        masked | !ENDPOINT_PROC_MASK
+    } else {
+        masked
+    }
+}
+
+/// Extract the generation counter from an endpoint.
+pub const fn endpoint_gen(e: Endpoint) -> GenNr {
+    e >> ENDPOINT_GEN_SHIFT
+}
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn special_endpoints_distinct() {
+        assert_ne!(ANY, SELF);
+        assert_ne!(ANY, NONE);
+        assert_ne!(SELF, NONE);
+    }
+
+    #[test]
+    fn encode_decode_positive_proc() {
+        let e = make_endpoint(3, 7);
+        assert_eq!(endpoint_gen(e), 3);
+        assert_eq!(endpoint_proc(e), 7);
+    }
+
+    #[test]
+    fn encode_decode_negative_proc() {
+        // Task endpoints have negative proc numbers (SYSTEM=-2, IDLE=-4, …).
+        let e = make_endpoint(1, -2);
+        assert_eq!(endpoint_gen(e), 1);
+        assert_eq!(endpoint_proc(e), -2);
+    }
+
+    #[test]
+    fn encode_decode_generation_zero() {
+        let e = make_endpoint(0, 11);
+        assert_eq!(endpoint_gen(e), 0);
+        assert_eq!(endpoint_proc(e), 11);
+    }
+
+    #[test]
+    fn proc_field_isolated_from_gen_field() {
+        // Bumping generation must not change the decoded proc_nr.
+        for g in 0..8 {
+            let e = make_endpoint(g, 5);
+            assert_eq!(endpoint_proc(e), 5, "gen={g}");
+        }
+    }
+}
diff --git a/kernel-shared/src/error.rs b/kernel-shared/src/error.rs
new file mode 100644
index 0000000..4c4c9a1
--- /dev/null
+++ b/kernel-shared/src/error.rs
@@ -0,0 +1,71 @@
+//! MINIX-style negative errno codes.
+//!
+//! Subset needed by Phase 2; more added as servers come online. Values match
+//! MINIX 3 `include/minix/errno.h`. Returning a negative `m_type` is how an
+//! IPC reply signals failure.
+
+pub const OK: i32 = 0;
+pub const EGENERIC: i32 = -1;
+pub const EPERM: i32 = -2;
+pub const ENOENT: i32 = -3;
+pub const ESRCH: i32 = -4;
+pub const EINTR: i32 = -5;
+pub const EIO: i32 = -6;
+pub const ENXIO: i32 = -7;
+pub const E2BIG: i32 = -8;
+pub const ENOEXEC: i32 = -9;
+pub const EBADF: i32 = -10;
+pub const ECHILD: i32 = -11;
+pub const EAGAIN: i32 = -12;
+pub const ENOMEM: i32 = -13;
+pub const EACCES: i32 = -14;
+pub const EFAULT: i32 = -15;
+pub const EINVAL: i32 = -21;
+pub const EDEADLK: i32 = -29;
+pub const ENOSYS: i32 = -44;
+
+// ---------------------------------------------------------------------------
+// IPC-specific errors — raised by the kernel's IPC subsystem.
+// ---------------------------------------------------------------------------
+
+pub const ELOCKED: i32 = -101;
+pub const EBADCALL: i32 = -102;
+pub const EBADSRCDST: i32 = -103;
+pub const ECALLDENIED: i32 = -104;
+pub const EDEADSRCDST: i32 = -105;
+pub const ENOTREADY: i32 = -106;
+pub const EBADREQUEST: i32 = -107;
+pub const ETRAPDENIED: i32 = -108;
+pub const EDONTREPLY: i32 = -109;
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn ok_is_zero() {
+        assert_eq!(OK, 0);
+    }
+
+    #[test]
+    fn all_errors_are_negative() {
+        for &e in &[
+            EGENERIC, EPERM, ENOENT, ESRCH, EINTR, EIO, ENXIO, E2BIG, ENOEXEC,
+            EBADF, ECHILD, EAGAIN, ENOMEM, EACCES, EFAULT, EINVAL, EDEADLK,
+            ENOSYS, ELOCKED, EBADCALL, EBADSRCDST, ECALLDENIED, EDEADSRCDST,
+            ENOTREADY, EBADREQUEST, ETRAPDENIED, EDONTREPLY,
+        ] {
+            assert!(e < 0, "errno {e} should be negative");
+        }
+    }
+
+    #[test]
+    fn ipc_errors_distinct_from_posix_errors() {
+        // The IPC range starts at -101 and must not collide with POSIX errnos.
+        for &posix in &[EGENERIC, EFAULT, EINVAL, ENOSYS] {
+            for &ipc in &[ELOCKED, EBADSRCDST, EDEADSRCDST, EDONTREPLY] {
+                assert_ne!(posix, ipc);
+            }
+        }
+    }
+}
diff --git a/kernel-shared/src/ipc_const.rs b/kernel-shared/src/ipc_const.rs
new file mode 100644
index 0000000..17076a9
--- /dev/null
+++ b/kernel-shared/src/ipc_const.rs
@@ -0,0 +1,47 @@
+//! IPC primitive numbers — values that go in `r1`/`x16` on the IPC trap.
+//!
+//! Matches MINIX 3 `include/minix/ipcconst.h`. The numbering is shared
+//! between the kernel's `do_ipc()` dispatch and the user-space stub.
+
+/// Blocking send. Caller blocks until the receiver accepts the message.
+pub const SEND: i32 = 1;
+/// Blocking receive. Caller blocks until a message arrives.
+pub const RECEIVE: i32 = 2;
+/// Atomic send + receive (the common case for client-server calls).
+pub const SENDREC: i32 = 3;
+/// Non-blocking notification — sets a bit in the receiver's notify bitmap.
+pub const NOTIFY: i32 = 4;
+/// Non-blocking send — returns `ENOTREADY` if the receiver is not waiting.
+pub const SENDNB: i32 = 5;
+/// Asynchronous send — the kernel walks the caller's async-send table.
+pub const SENDA: i32 = 16;
+
+/// Kernel-info introspection trap (separate from `SYS_GETINFO`); reserved
+/// but unused in Phase 2.
+pub const MINIX_KERNINFO: i32 = 32;
+
+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn all_primitives_distinct() {
+        let all = [SEND, RECEIVE, SENDREC, NOTIFY, SENDNB, SENDA, MINIX_KERNINFO];
